```typescript
// src/dashboard/services/realtime.service.ts
import { SocketStream } from '@fastify/websocket'
import { EventEmitter } from 'events'
import { Logger } from 'pino'

export class RealtimeService extends EventEmitter {
  private clients: Set<SocketStream> = new Set()
  private subscriptions: Map<SocketStream, Set<string>> = new Map()
  private heartbeatInterval?: NodeJS.Timeout

  constructor(private logger: Logger) {
    super()
  }

  // 添加客户端
  addClient(socket: SocketStream) {
    this.clients.add(socket)
    this.subscriptions.set(socket, new Set(['all']))
    this.logger.info(`Client connected. Total: ${this.clients.size}`)
  }

  // 移除客户端
  removeClient(socket: SocketStream) {
    this.clients.delete(socket)
    this.subscriptions.delete(socket)
    this.logger.info(`Client disconnected. Total: ${this.clients.size}`)
  }

  // 订阅频道
  subscribe(socket: SocketStream, channel: string) {
    const channels = this.subscriptions.get(socket)
    if (channels) {
      channels.add(channel)
      this.logger.info({ channel }, 'Client subscribed')
    }
  }

  // 取消订阅
  unsubscribe(socket: SocketStream, channel: string) {
    const channels = this.subscriptions.get(socket)
    if (channels) {
      channels.delete(channel)
      this.logger.info({ channel }, 'Client unsubscribed')
    }
  }

  // 广播消息（核心方法）
  broadcast(event: string, data: any) {
    const message = JSON.stringify({ event, data })

    for (const client of this.clients) {
      try {
        if (client.socket.readyState === 1) { // OPEN
          client.socket.send(message)
        }
      } catch (error) {
        this.logger.error(error, 'Failed to send message to client')
        this.removeClient(client)
      }
    }

    this.logger.debug({ event, clients: this.clients.size }, 'Broadcast sent')
  }

  // 发送到特定频道
  broadcastToChannel(channel: string, event: string, data: any) {
    const message = JSON.stringify({ event, data })

    for (const [client, channels] of this.subscriptions) {
      if (channels.has(channel) || channels.has('all')) {
        try {
          if (client.socket.readyState === 1) {
            client.socket.send(message)
          }
        } catch (error) {
          this.logger.error(error, 'Failed to send message')
          this.removeClient(client)
        }
      }
    }
  }

  // 广播系统指标
  broadcastMetrics(data: any) {
    this.broadcast('system.metrics', data)
  }

  // 广播迭代状态
  broadcastIterationStatus(data: any) {
    this.broadcast('iteration.status_changed', data)
  }

  // 广播 Agent 状态
  broadcastAgentStatus(data: any) {
    this.broadcast('agent.status_changed', data)
  }

  // 处理心跳响应
  handlePong(socket: SocketStream) {
    // 更新客户端最后活跃时间
    // 可用于检测僵尸连接
  }

  // 启动心跳检测
  startHeartbeat(intervalMs: number = 30000) {
    this.heartbeatInterval = setInterval(() => {
      const message = JSON.stringify({ event: 'ping', data: { timestamp: Date.now() } })

      for (const client of this.clients) {
        try {
          if (client.socket.readyState === 1) {
            client.socket.send(message)
          }
        } catch (error) {
          this.removeClient(client)
        }
      }
    }, intervalMs)
  }

  // 停止心跳
  stopHeartbeat() {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval)
    }
  }

  // 获取客户端数量
  getClientCount(): number {
    return this.clients.size
  }
}
```

